import java.util.*;
final class FanOutFanInPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String code){super(code);this.code=code;}String code(){return code;}}record Task(String id,String outcome,String value,int at,int index){}
    @SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){String mode=String.valueOf(input.get("mode"));if(!mode.equals("all")&&!mode.equals("first_success"))throw new PatternException("unknown_mode");if(mode.equals("first_success")&&Boolean.TRUE.equals(input.get("side_effecting")))throw new PatternException("fanout_not_allowed");List<Task>tasks=new ArrayList<>();Set<String>seen=new HashSet<>();int index=0;for(Map<String,Object>raw:(List<Map<String,Object>>)input.getOrDefault("tasks",List.of())){String id=String.valueOf(raw.get("id"));if(!seen.add(id))throw new PatternException("duplicate_task");tasks.add(new Task(id,String.valueOf(raw.get("outcome")),String.valueOf(raw.get("value")),((Number)raw.get("complete_at")).intValue(),index++));}tasks.sort(Comparator.comparingInt(Task::at).thenComparingInt(Task::index));List<String>completion=new ArrayList<>(),results=new ArrayList<>(),failures=new ArrayList<>();
        for(int position=0;position<tasks.size();position++){Task task=tasks.get(position);completion.add(task.id());if(task.outcome().equals("success")){results.add(task.id()+":"+task.value());if(mode.equals("first_success")){List<String>cancelled=tasks.subList(position+1,tasks.size()).stream().map(Task::id).toList();return Map.of("completion_order",completion,"results",results,"failures",failures,"cancelled",cancelled,"status","completed");}}else if(task.outcome().equals("failure"))failures.add(task.id());else throw new PatternException("unknown_outcome");}if(mode.equals("first_success"))throw new PatternException("all_tasks_failed");return Map.of("completion_order",completion,"results",results,"failures",failures,"cancelled",List.of(),"status",failures.isEmpty()?"completed":"partial");}}
